#include <iostream>
using namespace std;
int main() {
    int T, N, i, j;
    cin >> T;
    while (T--) {
        cin >> N;
        int arr[N];
        for (i = 0; i < N; i++) cin >> arr[i];
        int dp[N][2];
        dp[0][0] = (arr[0] % 2 == 0) ? 1 : 0;
        dp[0][1] = (arr[0] % 2 == 1) ? 1 : 0;
        for (i = 1; i < N; i++) {
            if (arr[i] % 2 == 0) {
                dp[i][0] = dp[i-1][1] + 1;
                dp[i][1] = dp[i-1][1];
            } else {
                dp[i][0] = dp[i-1][0];
                dp[i][1] = dp[i-1][0] + 1;
            }
        }
        cout << ((dp[N-1][0] > dp[N-1][1]) ? dp[N-1][0] : dp[N-1][1]) << endl;
    }
    return 0;
}

