            dp[0][1] = (arr[0] % 2 == 1) ? 1 : 0;
            for (int i = 1; i < N; i++) {
                if (arr[i] % 2 == 0) {
                    dp[i][0] = dp[i-1][1] + 1;
                    dp[i][1] = dp[i-1][1];
                } else {
                    dp[i][0] = dp[i-1][0];
                    dp[i][1] = dp[i-1][0] + 1;
