    if (i == 0) {
        T = parseInt(line);
    } else {
        input.push(line.split(' ').map(x => parseInt(x)));
    }
    i++;
    if (i > T * 2) {
        for (let j = 0; j < T; j++) {
            let N = input[j * 2][0];
            let arr = input[j * 2 + 1];
            let dp = new Array(N).fill(0).map(() => new Array(2).fill(0));
            dp[0][0] = (arr[0] % 2 == 0) ? 1 : 0;
            dp[0][1] = (arr[0] % 2 == 1) ? 1 : 0;
            for (let k = 1; k < N; k++) {
                if (arr[k] % 2 == 0) {
                    dp[k][0] = dp[k-1][1] + 1;
